  /* 避免 */
  transition: box-shadow 0.3s;
  box-shadow: 0 2px 8px rgba(0,0,0,.15);
}

/* 改用伪元素 */
.card::before {
  content: '';
  position: absolute;
  inset: 0;
  opacity: 0;
  box-shadow: 0 8px 24px rgba(0,0,0,.15);
  transition: opacity 0.3s;
}
.card:hover::before {
  opacity: 1;
}
```

### 3. 使用硬件加速

```css
/* 移动端特别推荐 */
.mobile-animated {
  -webkit-transform: translateZ(0);
  transform: translateZ(0);
}
```

### 4. 减少动画元素数量

```css
/* 应用虚拟化或懒加载，减少页面上同时动画的元素 */
```

### 5. 使用 will-change 做预优化

```css
/* 在动画开始前告知浏览器 */
.changing {
  will-change: transform;
}
```

